import numpy as np

def solve(grid):
    grid = np.array(grid)
    H, W = grid.shape

    # Base tile at position (0,0)
    base = grid[1:4, 1:4].copy()

    # Find modified tiles and their pattern
    modified = []
    mod_tile = None
    for ti in range(7):
        for tj in range(7):
            tile = grid[4*ti+1:4*ti+4, 4*tj+1:4*tj+4]
            if not np.array_equal(tile, base):
                modified.append((ti, tj))
                if mod_tile is None:
                    mod_tile = tile.copy()

    # Find new color
    base_colors = set(base.flatten())
    mod_colors = set(mod_tile.flatten())
    new_color = (mod_colors - base_colors).pop()

    # Build stamp
    stamp = (mod_tile == new_color).astype(int)

    # Find offset by trying all valid positions
    best_offset = None
    for r in range(5):  # 0..4 so stamp fits in 7x7
        for c in range(5):
            # Check if all modified tiles are covered
            stamp_positions = set()
            for i in range(3):
                for j in range(3):
                    if stamp[i][j]:
                        stamp_positions.add((r+i, c+j))
            if all(m in stamp_positions for m in modified):
                best_offset = (r, c)
                break
        if best_offset:
            break

    r, c = best_offset

    # Build output - start with base pattern everywhere
    output = grid.copy()
    # First reset all tiles to base
    for ti in range(7):
        for tj in range(7):
            output[4*ti+1:4*ti+4, 4*tj+1:4*tj+4] = base

    # Place modified tile where stamp says
    for i in range(3):
        for j in range(3):
            if stamp[i][j]:
                ti, tj = r+i, c+j
                if 0 <= ti < 7 and 0 <= tj < 7:
                    output[4*ti+1:4*ti+4, 4*tj+1:4*tj+4] = mod_tile

    return output.tolist()

